static void set_addr_win(struct fbtft_par *par, int xs, int ys, int xe, int ye)
{
    /* 列地址设置 */
    write_reg(par, 0x2A,
        (xs >> 8) & 0xFF, xs & 0xFF,
        (xe >> 8) & 0xFF, xe & 0xFF);

    /* 行地址设置 */
    write_reg(par, 0x2B,
        (ys >> 8) & 0xFF, ys & 0xFF,
        (ye >> 8) & 0xFF, ye & 0xFF);

    /* 内存写入命令 */
    write_reg(par, 0x2C);
}

static void handle_gpio_and_release(struct device *dev, const char *con_id)
{
    struct gpio_desc *gpiod;

    gpiod = gpiod_get_optional(dev, con_id, GPIOD_OUT_LOW);
    if (IS_ERR_OR_NULL(gpiod)) {
        if (IS_ERR(gpiod)) {
            dev_err(dev, "Failed to get GPIO: %ld\n", PTR_ERR(gpiod));
        } else {
            dev_info(dev, "Optional GPIO '%s' not present\n", con_id);
        }
        return;
    }

    gpiod_set_value(gpiod, 1);

    gpiod_put(gpiod);

    dev_info(dev, "GPIO '%s' set high and released\n", con_id);
}

static int init_display(struct fbtft_par *par)
{
    par->fbtftops.reset(par);
	mdelay(50);


    write_reg(par, 0xFF, 0xA5);
    write_reg(par, 0x9A, 0x08);
    write_reg(par, 0x9B, 0x08);
    write_reg(par, 0x9C, 0xB0);
    write_reg(par, 0x9D, 0x16);
    write_reg(par, 0x9E, 0xC4);
    write_reg(par, 0x8F, 0x55, 0x04);
    write_reg(par, 0x84, 0x90);
    write_reg(par, 0x83, 0x7B);
    write_reg(par, 0x85, 0x33);
    write_reg(par, 0x60, 0x00);
    write_reg(par, 0x70, 0x00);
    write_reg(par, 0x61, 0x02);
    write_reg(par, 0x71, 0x02);
    write_reg(par, 0x62, 0x04);
    write_reg(par, 0x72, 0x04);
    write_reg(par, 0x6C, 0x29);
    write_reg(par, 0x7C, 0x29);
    write_reg(par, 0x6D, 0x31);
    write_reg(par, 0x7D, 0x31);
    write_reg(par, 0x6E, 0x0F);
    write_reg(par, 0x7E, 0x0F);
    write_reg(par, 0x66, 0x21);
    write_reg(par, 0x76, 0x21);
    write_reg(par, 0x68, 0x3A);
    write_reg(par, 0x78, 0x3A);
    write_reg(par, 0x63, 0x07);
    write_reg(par, 0x73, 0x07);
    write_reg(par, 0x64, 0x05);
    write_reg(par, 0x74, 0x05);
    write_reg(par, 0x65, 0x02);
    write_reg(par, 0x75, 0x02);
    write_reg(par, 0x67, 0x23);
    write_reg(par, 0x77, 0x23);
    write_reg(par, 0x69, 0x08);
    write_reg(par, 0x79, 0x08);
    write_reg(par, 0x6A, 0x13);
    write_reg(par, 0x7A, 0x13);
    write_reg(par, 0x6B, 0x13);
    write_reg(par, 0x7B, 0x13);
    write_reg(par, 0x6F, 0x00);
    write_reg(par, 0x7F, 0x00);
    write_reg(par, 0x50, 0x00);
    write_reg(par, 0x52, 0xD6);
    write_reg(par, 0x53, 0x08);
    write_reg(par, 0x54, 0x08);
    write_reg(par, 0x55, 0x1E);
    write_reg(par, 0x56, 0x1C);

    /* GOA控制 */
    write_reg(par, 0xA0, 0x2B, 0x24, 0x00);
    write_reg(par, 0xA1, 0x87);
    write_reg(par, 0xA2, 0x86);
    write_reg(par, 0xA5, 0x00);
    write_reg(par, 0xA6, 0x00);
    write_reg(par, 0xA7, 0x00);
    write_reg(par, 0xA8, 0x36);
    write_reg(par, 0xA9, 0x7E);
    write_reg(par, 0xAA, 0x7E);
    write_reg(par, 0xB9, 0x85);
    write_reg(par, 0xBA, 0x84);
    write_reg(par, 0xBB, 0x83);
    write_reg(par, 0xBC, 0x82);
    write_reg(par, 0xBD, 0x81);
    write_reg(par, 0xBE, 0x80);
    write_reg(par, 0xBF, 0x01);
    write_reg(par, 0xC0, 0x02);
    write_reg(par, 0xC1, 0x00);
    write_reg(par, 0xC2, 0x00);
    write_reg(par, 0xC3, 0x00);
    write_reg(par, 0xC4, 0x33);
    write_reg(par, 0xC5, 0x7E);
    write_reg(par, 0xC6, 0x7E);
    write_reg(par, 0xC8, 0x33, 0x33);
    write_reg(par, 0xC9, 0x68);
    write_reg(par, 0xCA, 0x69);
    write_reg(par, 0xCB, 0x6A);
    write_reg(par, 0xCC, 0x6B);
    write_reg(par, 0xCD, 0x33, 0x33);
    write_reg(par, 0xCE, 0x6C);
    write_reg(par, 0xCF, 0x6D);
    write_reg(par, 0xD0, 0x6E);
    write_reg(par, 0xD1, 0x6F);
    write_reg(par, 0xAB, 0x03, 0x67);
    write_reg(par, 0xAC, 0x03, 0x6B);
    write_reg(par, 0xAD, 0x03, 0x68);
    write_reg(par, 0xAE, 0x03, 0x6C);
    write_reg(par, 0xB3, 0x00);
    write_reg(par, 0xB4, 0x00);
    write_reg(par, 0xB5, 0x00);
    write_reg(par, 0xB6, 0x32);
    write_reg(par, 0xB7, 0x7E);
    write_reg(par, 0xB8, 0x7E);

    /* 时序控制 */
    write_reg(par, 0xE0, 0x00);
    write_reg(par, 0xE1, 0x03, 0x0F);
    write_reg(par, 0xE2, 0x04);
    write_reg(par, 0xE3, 0x01);
    write_reg(par, 0xE4, 0x0E);
    write_reg(par, 0xE5, 0x01);
    write_reg(par, 0xE6, 0x19);
    write_reg(par, 0xE7, 0x10);
    write_reg(par, 0xE8, 0x10);
    write_reg(par, 0xEA, 0x12);
    write_reg(par, 0xEB, 0xD0);
    write_reg(par, 0xEC, 0x04);
    write_reg(par, 0xED, 0x07);
    write_reg(par, 0xEE, 0x07);
    write_reg(par, 0xEF, 0x09);
    write_reg(par, 0xF0, 0xD0);
    write_reg(par, 0xF1, 0x0E);
	
	//write_reg(par, 0xF9, 0x17);
    write_reg(par, 0xF2, 0x2C, 0x1B, 0x0B, 0x20);
	write_reg(par, 0xF9, 0x17);

    /* 1 dot */
    write_reg(par, 0xE9, 0x29);
    write_reg(par, 0xEC, 0x04);

    /* TE配置 */
    write_reg(par, 0x35, 0x00);
    write_reg(par, 0x44, 0x00, 0x10);
    write_reg(par, 0x46, 0x10);

    /* 设置像素格式 */
    write_reg(par, 0xFF, 0x00); // Exit command mode
    write_reg(par, 0x3A, 0x05); // 16bpp格式
    write_reg(par, 0x36, 0x60);

    /* 退出睡眠模式 */
    write_reg(par, 0x11);
    mdelay(220);

    /* 开启显示 */
    write_reg(par, 0x29);
    mdelay(200);

    set_addr_win(par, 0, 0, par->info->var.xres - 1, par->info->var.yres - 1);
    msleep(10);
    gpiod_set_value(par->gpio.dc, 1);
    size_t total_size = sizeof(Untitled_map);
    size_t offset = 0;
    const size_t chunk_size = 4096; // SPI传输块大小

    dev_info(par->info->device, "Start sending logo (%zu bytes)...\n", total_size);

    while (offset < total_size) {
        size_t bytes_to_send = min(chunk_size, total_size - offset);

        int ret = fbtft_write_spi(par, (u8 *)Untitled_map + offset, bytes_to_send);
        if (ret < 0) {
            dev_err(par->info->device, "SPI write error at offset %zu: %d\n", offset, ret);
            return ret;
        }

        offset += bytes_to_send;
        // 添加小延时防止SPI过载
        udelay(10);
    }

    msleep(20);

    handle_gpio_and_release(par->info->device, BACKLIGHT_GPIO);

    dev_info(par->info->device, "NV3007 initialized\n");
    return 0;
}

static int blank(struct fbtft_par *par, bool on)
{
    if (on) {
        write_reg(par, 0x28); // Display OFF
        dev_dbg(par->info->device, "Display blanked\n");
    } else {
        write_reg(par, 0x29); // Display ON
        dev_dbg(par->info->device, "Display unblanked\n");
    }
    return 0;
}

static struct fbtft_display display = {
    .regwidth = 8,
    .width = WIDTH,
    .height = HEIGHT,
    .gamma_num = 2,
    .gamma_len = 4,
    .fps = 30,
    .bpp = 16,
    .fbtftops = {
        .init_display = init_display,
        .set_addr_win = set_addr_win,
        .blank = blank,
    },
};

FBTFT_REGISTER_DRIVER(DRVNAME, "nv3007", &display);

MODULE_ALIAS("spi:" DRVNAME);
MODULE_ALIAS("platform:" DRVNAME);
MODULE_ALIAS("spi:nv3007");
MODULE_ALIAS("platform:nv3007");

MODULE_DESCRIPTION("FB driver for the NV3007 LCD Controller");
MODULE_AUTHOR("Your Name");
MODULE_LICENSE("GPL");
